44: /**
45:  * A {@link Records} implementation backed by a ByteBuffer. This is used only for reading or
46:  * modifying in-place an existing buffer of record batches. To create a new buffer see {@link MemoryRecordsBuilder},
47:  * or one of the {@link #builder(ByteBuffer, byte, Compression, TimestampType, long)} variants.
48:  */
49: public class MemoryRecords extends AbstractRecords {
50:     public static final MemoryRecords EMPTY = MemoryRecords.readableRecords(ByteBuffer.allocate(0));
51: 
52:     private final ByteBuffer buffer;
53: 
54:     private final Iterable<MutableRecordBatch> batches = this::batchIterator;
55: 
56:     private int validBytes = -1;
57: 
58:     // Construct a writable memory records
59:     private MemoryRecords(ByteBuffer buffer) {
60:         Objects.requireNonNull(buffer, "buffer should not be null");
61:         this.buffer = buffer;
62:     }
63: 
64:     @Override
65:     public int sizeInBytes() {
66:         return buffer.limit();
67:     }
68: 
69:     @Override
70:     public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
71:         if (((long) position) + length > buffer.limit())
72:             throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
73:                     + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());
74: 
75:         return Utils.tryWriteTo(channel, position, length, buffer);
76:     }
77: 
78:     /**
79:      * Write all records to the given channel (including partial records).
80:      * @param channel The channel to write to
81:      * @return The number of bytes written
82:      * @throws IOException For any IO errors writing to the channel
83:      */
84:     public int writeFullyTo(GatheringByteChannel channel) throws IOException {
85:         buffer.mark();
86:         int written = 0;
87:         while (written < sizeInBytes())
88:             written += channel.write(buffer);
89:         buffer.reset();
90:         return written;
91:     }
92: 
93:     /**
94:      * The total number of bytes in this message set not including any partial, trailing messages. This
95:      * may be smaller than what is returned by {@link #sizeInBytes()}.
96:      * @return The number of valid bytes
97:      */
98:     public int validBytes() {
99:         if (validBytes >= 0)
100:             return validBytes;
101: 
102:         int bytes = 0;
103:         for (RecordBatch batch : batches())
104:             bytes += batch.sizeInBytes();
105: 
106:         this.validBytes = bytes;
107:         return bytes;
108:     }
