110:     @Override
111:     public AbstractIterator<MutableRecordBatch> batchIterator() {
112:         return new RecordBatchIterator<>(new ByteBufferLogInputStream(buffer.duplicate(), Integer.MAX_VALUE));
113:     }
114: 
115:     /**
116:      * Validates the header of the first batch and returns batch size.
117:      * @return first batch size including LOG_OVERHEAD if buffer contains header up to
118:      *         magic byte, null otherwise
119:      * @throws CorruptRecordException if record size or magic is invalid
120:      */
121:     public Integer firstBatchSize() {
122:         if (buffer.remaining() < HEADER_SIZE_UP_TO_MAGIC)
123:             return null;
124:         return new ByteBufferLogInputStream(buffer, Integer.MAX_VALUE).nextBatchSize();
125:     }
126: 
127:     /**
128:      * Filter the records into the provided ByteBuffer.
129:      *
130:      * @param filter                      The filter function
131:      * @param destinationBuffer           The byte buffer to write the filtered records to
132:      * @param decompressionBufferSupplier The supplier of ByteBuffer(s) used for decompression if supported. For small
133:      *                                    record batches, allocating a potentially large buffer (64 KB for LZ4) will
134:      *                                    dominate the cost of decompressing and iterating over the records in the
135:      *                                    batch. As such, a supplier that reuses buffers will have a significant
136:      *                                    performance impact.
137:      * @return A FilterResult with a summary of the output (for metrics) and potentially an overflow buffer
138:      */
139:     public FilterResult filterTo(RecordFilter filter, ByteBuffer destinationBuffer, BufferSupplier decompressionBufferSupplier) {
140:         return filterTo(batches(), filter, destinationBuffer, decompressionBufferSupplier);
141:     }
142: 
143:     /**
144:      * Note: This method is also used to convert the first timestamp of the batch (which is usually the timestamp of the first record)
145:      * to the delete horizon of the tombstones or txn markers which are present in the batch.
146:      */
147:     private static FilterResult filterTo(Iterable<MutableRecordBatch> batches, RecordFilter filter,
148:                                          ByteBuffer destinationBuffer, BufferSupplier decompressionBufferSupplier) {
149:         FilterResult filterResult = new FilterResult(destinationBuffer);
150:         ByteBufferOutputStream bufferOutputStream = new ByteBufferOutputStream(destinationBuffer);
151:         for (MutableRecordBatch batch : batches) {
152:             final BatchRetentionResult batchRetentionResult = filter.checkBatchRetention(batch);
153:             final boolean containsMarkerForEmptyTxn = batchRetentionResult.containsMarkerForEmptyTxn;
154:             final BatchRetention batchRetention = batchRetentionResult.batchRetention;
155: 
156:             filterResult.bytesRead += batch.sizeInBytes();
157: 
158:             if (batchRetention == BatchRetention.DELETE)
159:                 continue;
160: 
161:             final BatchFilterResult iterationResult = filterBatch(batch, decompressionBufferSupplier, filterResult,
162:                 filter);
163:             List<Record> retainedRecords = iterationResult.retainedRecords;
164:             boolean containsTombstones = iterationResult.containsTombstones;
165:             boolean writeOriginalBatch = iterationResult.writeOriginalBatch;
166:             long maxOffset = iterationResult.maxOffset;
167: 
168:             if (!retainedRecords.isEmpty()) {
169:                 // we check if the delete horizon should be set to a new value
170:                 // in which case, we need to reset the base timestamp and overwrite the timestamp deltas
171:                 // if the batch does not contain tombstones, then we don't need to overwrite batch
172:                 boolean needToSetDeleteHorizon = (containsTombstones || containsMarkerForEmptyTxn) &&
173:                     batch.deleteHorizonMs().isEmpty();
174:                 if (writeOriginalBatch && !needToSetDeleteHorizon) {
175:                     batch.writeTo(bufferOutputStream);
176:                     filterResult.updateRetainedBatchMetadata(batch, retainedRecords.size(), false);
177:                 } else {
178:                     long deleteHorizonMs;
179:                     if (needToSetDeleteHorizon)
180:                         deleteHorizonMs = filter.currentTime + filter.deleteRetentionMs;
181:                     else
182:                         deleteHorizonMs = batch.deleteHorizonMs().orElse(RecordBatch.NO_TIMESTAMP);
183:                     try (final MemoryRecordsBuilder builder = buildRetainedRecordsInto(batch, retainedRecords,
184:                             bufferOutputStream, deleteHorizonMs)) {
185:                         MemoryRecords records = builder.build();
186:                         int filteredBatchSize = records.sizeInBytes();
187:                         MemoryRecordsBuilder.RecordsInfo info = builder.info();
188:                         filterResult.updateRetainedBatchMetadata(info.maxTimestamp, info.shallowOffsetOfMaxTimestamp,
189:                             maxOffset, retainedRecords.size(), filteredBatchSize);
190:                     }
191:                 }
192:             } else if (batchRetention == BatchRetention.RETAIN_EMPTY) {
193:                 if (batch.magic() < RecordBatch.MAGIC_VALUE_V2) // should never happen
194:                     throw new IllegalStateException("Empty batches are only supported for magic v2 and above");
195: 
196:                 bufferOutputStream.ensureRemaining(DefaultRecordBatch.RECORD_BATCH_OVERHEAD);
197:                 DefaultRecordBatch.writeEmptyHeader(bufferOutputStream.buffer(), RecordBatch.CURRENT_MAGIC_VALUE, batch.producerId(),
198:                         batch.producerEpoch(), batch.baseSequence(), batch.baseOffset(), batch.lastOffset(),
199:                         batch.partitionLeaderEpoch(), batch.timestampType(), batch.maxTimestamp(),
200:                         batch.isTransactional(), batch.isControlBatch());
201:                 filterResult.updateRetainedBatchMetadata(batch, 0, true);
202:             }
203: 
204:             // If we had to allocate a new buffer to fit the filtered buffer (see KAFKA-5316), return early to
205:             // avoid the need for additional allocations.
206:             ByteBuffer outputBuffer = bufferOutputStream.buffer();
207:             if (outputBuffer != destinationBuffer) {
208:                 filterResult.outputBuffer = outputBuffer;
209:                 return filterResult;
210:             }
211:         }
212: 
213:         return filterResult;
214:     }
215: 
216:     private static BatchFilterResult filterBatch(RecordBatch batch,
217:                                                  BufferSupplier decompressionBufferSupplier,
218:                                                  FilterResult filterResult,
219:                                                  RecordFilter filter) {
220:         try (final CloseableIterator<Record> iterator = batch.streamingIterator(decompressionBufferSupplier)) {
221:             long maxOffset = -1;
222:             boolean containsTombstones = false;
223:             // Convert records with old record versions
224:             boolean writeOriginalBatch = batch.magic() >= RecordBatch.CURRENT_MAGIC_VALUE;
225:             List<Record> retainedRecords = new ArrayList<>();
226:             while (iterator.hasNext()) {
227:                 Record record = iterator.next();
228:                 filterResult.messagesRead += 1;
229: 
230:                 if (filter.shouldRetainRecord(batch, record)) {
231:                     if (record.offset() > maxOffset)
232:                         maxOffset = record.offset();
233: 
234:                     retainedRecords.add(record);
235: 
236:                     if (!record.hasValue()) {
237:                         containsTombstones = true;
238:                     }
239:                 } else {
240:                     writeOriginalBatch = false;
241:                 }
242:             }
243:             return new BatchFilterResult(retainedRecords, writeOriginalBatch, containsTombstones, maxOffset);
244:         }
245:     }
