419:         private void updateRetainedBatchMetadata(long maxTimestamp, long shallowOffsetOfMaxTimestamp, long maxOffset,
420:                                                  int messagesRetained, int bytesRetained) {
421:             validateBatchMetadata(maxTimestamp, shallowOffsetOfMaxTimestamp, maxOffset);
422:             if (maxTimestamp > this.maxTimestamp) {
423:                 this.maxTimestamp = maxTimestamp;
424:                 this.shallowOffsetOfMaxTimestamp = shallowOffsetOfMaxTimestamp;
425:             }
426:             this.maxOffset = Math.max(maxOffset, this.maxOffset);
427:             this.messagesRetained += messagesRetained;
428:             this.bytesRetained += bytesRetained;
