    /**
     * Creates a {@link MemoryRecordsBuilder} with full control over magic version, compression,
     * timestamp type, log-append time, producer identity, transactional flag, and partition leader
     * epoch. The control-batch flag is set to {@code false}.
     *
     * @param buffer               the buffer to write the encoded batch into; must not be {@code null}
     * @param magic                the record format magic byte
     * @param compression          the compression codec to apply to record data
     * @param timestampType        the timestamp type
     * @param baseOffset           the base offset of the first record in the batch
     * @param logAppendTime        the log-append timestamp;
     *                             use {@link RecordBatch#NO_TIMESTAMP} if not applicable
     * @param producerId           the idempotent/transactional producer id, or
     *                             {@link RecordBatch#NO_PRODUCER_ID}
     * @param producerEpoch        the producer epoch, or {@link RecordBatch#NO_PRODUCER_EPOCH}
     * @param baseSequence         the base sequence number, or {@link RecordBatch#NO_SEQUENCE}
     * @param isTransactional      {@code true} if the batch belongs to a transaction
     * @param partitionLeaderEpoch the partition leader epoch at the time of writing
     * @return a new {@link MemoryRecordsBuilder} ready to accept records
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               byte magic,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset,
                                               long logAppendTime,
                                               long producerId,
                                               short producerEpoch,
                                               int baseSequence,
                                               boolean isTransactional,
                                               int partitionLeaderEpoch) {
        return builder(buffer, magic, compression, timestampType, baseOffset,
                logAppendTime, producerId, producerEpoch, baseSequence, isTransactional, false, partitionLeaderEpoch);
    }

    /**
     * Creates a {@link MemoryRecordsBuilder} with full control over all batch header fields,
     * including the control-batch flag.
     *
     * @param buffer               the buffer to write the encoded batch into; must not be {@code null}
     * @param magic                the record format magic byte
     * @param compression          the compression codec to apply to record data
     * @param timestampType        the timestamp type
     * @param baseOffset           the base offset of the first record in the batch
     * @param logAppendTime        the log-append timestamp;
     *                             use {@link RecordBatch#NO_TIMESTAMP} if not applicable
     * @param producerId           the idempotent/transactional producer id, or
     *                             {@link RecordBatch#NO_PRODUCER_ID}
     * @param producerEpoch        the producer epoch, or {@link RecordBatch#NO_PRODUCER_EPOCH}
     * @param baseSequence         the base sequence number, or {@link RecordBatch#NO_SEQUENCE}
     * @param isTransactional      {@code true} if the batch belongs to a transaction
     * @param isControlBatch       {@code true} if this is a control batch (e.g. transaction markers)
     * @param partitionLeaderEpoch the partition leader epoch at the time of writing
     * @return a new {@link MemoryRecordsBuilder} ready to accept records
     */
    public static MemoryRecordsBuilder builder(ByteBuffer buffer,
                                               byte magic,
                                               Compression compression,
                                               TimestampType timestampType,
                                               long baseOffset,
                                               long logAppendTime,
                                               long producerId,
                                               short producerEpoch,
                                               int baseSequence,
                                               boolean isTransactional,
                                               boolean isControlBatch,
                                               int partitionLeaderEpoch) {
        return new MemoryRecordsBuilder(buffer, magic, compression, timestampType, baseOffset,
                logAppendTime, producerId, producerEpoch, baseSequence, isTransactional, isControlBatch, partitionLeaderEpoch,
                buffer.remaining());
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects in a single
     * batch using the current magic version, the specified compression, and a base offset of 0.
     *
     * @param compression the compression codec to apply
     * @param records     the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(Compression compression, SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, compression, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects in a single
     * batch using the current magic version, the specified compression, a base offset of 0, and
     * the given partition leader epoch.
     *
     * @param compression          the compression codec to apply
     * @param partitionLeaderEpoch the partition leader epoch to embed in the batch header
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(Compression compression, int partitionLeaderEpoch, SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, 0L, compression, TimestampType.CREATE_TIME,
                RecordBatch.NO_PRODUCER_ID, RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE,
                partitionLeaderEpoch, false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects using the
     * specified magic version, the specified compression, a base offset of 0, and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param magic       the record format magic byte
     * @param compression the compression codec to apply
     * @param records     the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(byte magic, Compression compression, SimpleRecord... records) {
        return withRecords(magic, 0L, compression, TimestampType.CREATE_TIME, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects using the
     * current magic version, the specified compression, the given initial offset, and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset the base offset to assign to the first record
     * @param compression   the compression codec to apply
     * @param records       the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(long initialOffset, Compression compression, SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, initialOffset, compression, TimestampType.CREATE_TIME,
                records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects using the
     * specified magic version, compression, initial offset, and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param magic         the record format magic byte
     * @param initialOffset the base offset to assign to the first record
     * @param compression   the compression codec to apply
     * @param records       the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(byte magic, long initialOffset, Compression compression, SimpleRecord... records) {
        return withRecords(magic, initialOffset, compression, TimestampType.CREATE_TIME, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects using the
     * current magic version, the specified compression and initial offset, and the given partition
     * leader epoch. The timestamp type is {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param partitionLeaderEpoch the partition leader epoch to embed in the batch header
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(long initialOffset, Compression compression, int partitionLeaderEpoch, SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, initialOffset, compression, TimestampType.CREATE_TIME, RecordBatch.NO_PRODUCER_ID,
                RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE, partitionLeaderEpoch, false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing idempotent (non-transactional) records. The
     * current magic version and {@link TimestampType#CREATE_TIME} are used, with a base offset
     * of 0 and {@link RecordBatch#NO_PARTITION_LEADER_EPOCH}.
     *
     * @param compression   the compression codec to apply
     * @param producerId    the idempotent producer id
     * @param producerEpoch the producer epoch
     * @param baseSequence  the base sequence number for duplicate detection
     * @param records       the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withIdempotentRecords(Compression compression, long producerId,
                                                      short producerEpoch, int baseSequence, SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, 0L, compression, TimestampType.CREATE_TIME, producerId, producerEpoch,
                baseSequence, RecordBatch.NO_PARTITION_LEADER_EPOCH, false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing idempotent records with the specified magic
     * version, initial offset, compression, full producer identity, and partition leader epoch.
     *
     * @param magic                the record format magic byte
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param producerId           the idempotent producer id
     * @param producerEpoch        the producer epoch
     * @param baseSequence         the base sequence number for duplicate detection
     * @param partitionLeaderEpoch the partition leader epoch
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withIdempotentRecords(byte magic, long initialOffset, Compression compression,
                                                      long producerId, short producerEpoch, int baseSequence,
                                                      int partitionLeaderEpoch, SimpleRecord... records) {
        return withRecords(magic, initialOffset, compression, TimestampType.CREATE_TIME, producerId, producerEpoch,
                baseSequence, partitionLeaderEpoch, false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing idempotent records using the current magic
     * version, the given initial offset, compression, full producer identity, and partition leader
     * epoch. The timestamp type is {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param producerId           the idempotent producer id
     * @param producerEpoch        the producer epoch
     * @param baseSequence         the base sequence number for duplicate detection
     * @param partitionLeaderEpoch the partition leader epoch
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withIdempotentRecords(long initialOffset, Compression compression, long producerId,
                                                      short producerEpoch, int baseSequence, int partitionLeaderEpoch,
                                                      SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, initialOffset, compression, TimestampType.CREATE_TIME,
                producerId, producerEpoch, baseSequence, partitionLeaderEpoch, false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing transactional records. The current magic version,
     * {@link TimestampType#CREATE_TIME}, a base offset of 0, and
     * {@link RecordBatch#NO_PARTITION_LEADER_EPOCH} are used.
     *
     * @param compression   the compression codec to apply
     * @param producerId    the transactional producer id
     * @param producerEpoch the producer epoch
     * @param baseSequence  the base sequence number for duplicate detection
     * @param records       the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised transactional batch
     */
    public static MemoryRecords withTransactionalRecords(Compression compression, long producerId,
                                                         short producerEpoch, int baseSequence, SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, 0L, compression, TimestampType.CREATE_TIME,
                producerId, producerEpoch, baseSequence, RecordBatch.NO_PARTITION_LEADER_EPOCH, true, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing transactional records with the specified magic
     * version, initial offset, compression, full producer identity, and partition leader epoch.
     *
     * @param magic                the record format magic byte
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param producerId           the transactional producer id
     * @param producerEpoch        the producer epoch
     * @param baseSequence         the base sequence number
     * @param partitionLeaderEpoch the partition leader epoch
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised transactional batch
     */
    public static MemoryRecords withTransactionalRecords(byte magic, long initialOffset, Compression compression,
                                                         long producerId, short producerEpoch, int baseSequence,
                                                         int partitionLeaderEpoch, SimpleRecord... records) {
        return withRecords(magic, initialOffset, compression, TimestampType.CREATE_TIME, producerId, producerEpoch,
                baseSequence, partitionLeaderEpoch, true, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing transactional records using the current magic
     * version, the given initial offset, compression, full producer identity, and partition leader
     * epoch. The timestamp type is {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param producerId           the transactional producer id
     * @param producerEpoch        the producer epoch
     * @param baseSequence         the base sequence number
     * @param partitionLeaderEpoch the partition leader epoch
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised transactional batch
     */
    public static MemoryRecords withTransactionalRecords(long initialOffset, Compression compression, long producerId,
                                                         short producerEpoch, int baseSequence, int partitionLeaderEpoch,
                                                         SimpleRecord... records) {
        return withTransactionalRecords(RecordBatch.CURRENT_MAGIC_VALUE, initialOffset, compression,
                producerId, producerEpoch, baseSequence, partitionLeaderEpoch, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects using the
     * specified magic version, initial offset, compression, and timestamp type. No idempotent or
     * transactional metadata is embedded.
     *
     * @param magic         the record format magic byte
     * @param initialOffset the base offset to assign to the first record
     * @param compression   the compression codec to apply
     * @param timestampType the timestamp type
     * @param records       the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withRecords(byte magic, long initialOffset, Compression compression,
                                            TimestampType timestampType, SimpleRecord... records) {
        return withRecords(magic, initialOffset, compression, timestampType, RecordBatch.NO_PRODUCER_ID,
                RecordBatch.NO_PRODUCER_EPOCH, RecordBatch.NO_SEQUENCE, RecordBatch.NO_PARTITION_LEADER_EPOCH,
                false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing the given {@link SimpleRecord} objects with full
     * control over all batch header fields. This is the most general {@code withRecords} overload;
     * all other overloads delegate to this method.
     *
     * <p><b>Performance note:</b> The method estimates the required buffer size upfront based on
     * {@link AbstractRecords#estimateSizeInBytes} and uses a resizable
     * {@link ByteBufferOutputStream} to handle cases where the estimate is too small. Only a
     * single batch is created per call.
     *
     * @param magic                the record format magic byte
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param timestampType        the timestamp type
     * @param producerId           the idempotent/transactional producer id, or
     *                             {@link RecordBatch#NO_PRODUCER_ID}
     * @param producerEpoch        the producer epoch, or {@link RecordBatch#NO_PRODUCER_EPOCH}
     * @param baseSequence         the base sequence number, or {@link RecordBatch#NO_SEQUENCE}
     * @param partitionLeaderEpoch the partition leader epoch
     * @param isTransactional      {@code true} if the batch belongs to a transaction
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch, or
     *         {@link #EMPTY} if {@code records} is empty
     */
    public static MemoryRecords withRecords(byte magic, long initialOffset, Compression compression,
                                            TimestampType timestampType, long producerId, short producerEpoch,
                                            int baseSequence, int partitionLeaderEpoch, boolean isTransactional,
                                            SimpleRecord... records) {
        if (records.length == 0)
            return MemoryRecords.EMPTY;
        int sizeEstimate = AbstractRecords.estimateSizeInBytes(magic, compression.type(), Arrays.asList(records));
        ByteBufferOutputStream bufferStream = new ByteBufferOutputStream(sizeEstimate);
        long logAppendTime = RecordBatch.NO_TIMESTAMP;
        if (timestampType == TimestampType.LOG_APPEND_TIME)
            logAppendTime = System.currentTimeMillis();
        try (final MemoryRecordsBuilder builder = new MemoryRecordsBuilder(bufferStream, magic, compression, timestampType,
                initialOffset, logAppendTime, producerId, producerEpoch, baseSequence, isTransactional, false,
                partitionLeaderEpoch, sizeEstimate)) {
            for (SimpleRecord record : records)
                builder.append(record);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single end-of-transaction control batch for the
     * given producer, using offset 0 and the current wall-clock time as the timestamp.
     *
     * @param producerId    the transactional producer id
     * @param producerEpoch the producer epoch
     * @param marker        the {@link EndTransactionMarker} describing the transaction outcome
     * @return an immutable {@link MemoryRecords} containing the end-transaction control batch
     */
    public static MemoryRecords withEndTransactionMarker(long producerId, short producerEpoch, EndTransactionMarker marker) {
        return withEndTransactionMarker(0L, System.currentTimeMillis(), RecordBatch.NO_PARTITION_LEADER_EPOCH,
                producerId, producerEpoch, marker);
    }

    /**
     * Builds a {@link MemoryRecords} containing a single end-of-transaction control batch for the
     * given producer, using offset 0 and the specified timestamp.
     *
     * @param timestamp     the timestamp to embed in the batch header (milliseconds since epoch)
     * @param producerId    the transactional producer id
     * @param producerEpoch the producer epoch
     * @param marker        the {@link EndTransactionMarker} describing the transaction outcome
     * @return an immutable {@link MemoryRecords} containing the end-transaction control batch
     */
    public static MemoryRecords withEndTransactionMarker(long timestamp, long producerId, short producerEpoch,
                                                         EndTransactionMarker marker) {
        return withEndTransactionMarker(0L, timestamp, RecordBatch.NO_PARTITION_LEADER_EPOCH, producerId,
                producerEpoch, marker);
    }

    /**
     * Builds a {@link MemoryRecords} containing a single end-of-transaction control batch with
     * the given initial offset, timestamp, partition leader epoch, and producer identity.
     *
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param partitionLeaderEpoch the partition leader epoch
     * @param producerId           the transactional producer id
     * @param producerEpoch        the producer epoch
     * @param marker               the {@link EndTransactionMarker} describing the transaction outcome
     * @return an immutable {@link MemoryRecords} containing the end-transaction control batch
     */
    public static MemoryRecords withEndTransactionMarker(long initialOffset, long timestamp, int partitionLeaderEpoch,
                                                         long producerId, short producerEpoch,
                                                         EndTransactionMarker marker) {
        int endTxnMarkerBatchSize = DefaultRecordBatch.RECORD_BATCH_OVERHEAD + marker.endTxnMarkerValueSize();
        ByteBuffer buffer = ByteBuffer.allocate(endTxnMarkerBatchSize);
        writeEndTransactionalMarker(buffer, initialOffset, timestamp, partitionLeaderEpoch, producerId,
                producerEpoch, marker);
        buffer.flip();
        return MemoryRecords.readableRecords(buffer);
    }

    /**
     * Encodes a single end-of-transaction control batch directly into the given {@link ByteBuffer}
     * starting at its current position.
     *
     * <p>This method is a lower-level alternative to
     * {@link #withEndTransactionMarker(long, long, int, long, short, EndTransactionMarker)} for
     * callers that already manage their own buffer.
     *
     * @param buffer               the destination buffer; must have sufficient remaining capacity
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param partitionLeaderEpoch the partition leader epoch
     * @param producerId           the transactional producer id
     * @param producerEpoch        the producer epoch
     * @param marker               the {@link EndTransactionMarker} describing the transaction outcome
     */
    public static void writeEndTransactionalMarker(ByteBuffer buffer, long initialOffset, long timestamp,
                                                   int partitionLeaderEpoch, long producerId, short producerEpoch,
                                                   EndTransactionMarker marker) {
        boolean isTransactional = true;
        try (MemoryRecordsBuilder builder = new MemoryRecordsBuilder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, Compression.NONE,
                TimestampType.CREATE_TIME, initialOffset, timestamp, producerId, producerEpoch,
                RecordBatch.NO_SEQUENCE, isTransactional, true, partitionLeaderEpoch,
                buffer.capacity())
        ) {
            builder.appendEndTxnMarker(timestamp, marker);
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link LeaderChangeMessage}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset       the base offset to assign to the control batch
     * @param timestamp           the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch         the partition leader epoch
     * @param buffer              the buffer to write the encoded batch into
     * @param leaderChangeMessage the {@link LeaderChangeMessage} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withLeaderChangeMessage(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        LeaderChangeMessage leaderChangeMessage
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendLeaderChangeMessage(timestamp, leaderChangeMessage);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link SnapshotHeaderRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch          the partition leader epoch
     * @param buffer               the buffer to write the encoded batch into
     * @param snapshotHeaderRecord the {@link SnapshotHeaderRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withSnapshotHeaderRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        SnapshotHeaderRecord snapshotHeaderRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendSnapshotHeaderMessage(timestamp, snapshotHeaderRecord);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link SnapshotFooterRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch          the partition leader epoch
     * @param buffer               the buffer to write the encoded batch into
     * @param snapshotFooterRecord the {@link SnapshotFooterRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withSnapshotFooterRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        SnapshotFooterRecord snapshotFooterRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendSnapshotFooterMessage(timestamp, snapshotFooterRecord);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link KRaftVersionRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset      the base offset to assign to the control batch
     * @param timestamp          the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch        the partition leader epoch
     * @param buffer             the buffer to write the encoded batch into
     * @param kraftVersionRecord the {@link KRaftVersionRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withKRaftVersionRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        KRaftVersionRecord kraftVersionRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendKRaftVersionMessage(timestamp, kraftVersionRecord);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link VotersRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset the base offset to assign to the control batch
     * @param timestamp     the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch   the partition leader epoch
     * @param buffer        the buffer to write the encoded batch into
     * @param votersRecord  the {@link VotersRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withVotersRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        VotersRecord votersRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendVotersMessage(timestamp, votersRecord);
            return builder.build();
        }
    }

    private static MemoryRecordsBuilder createKraftControlRecordBuilder(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer
    ) {
        return new MemoryRecordsBuilder(
            buffer,
            RecordBatch.CURRENT_MAGIC_VALUE,
            Compression.NONE,
            TimestampType.CREATE_TIME,
            initialOffset,
            timestamp,
            RecordBatch.NO_PRODUCER_ID,
            RecordBatch.NO_PRODUCER_EPOCH,
            RecordBatch.NO_SEQUENCE,
            false,
            true,
            leaderEpoch,
            buffer.capacity()
        );
    }
}

