     * @param timestamp     the timestamp to embed in the batch header (milliseconds since epoch)
     * @param producerId    the transactional producer id
     * @param producerEpoch the producer epoch
     * @param marker        the {@link EndTransactionMarker} describing the transaction outcome
     * @return an immutable {@link MemoryRecords} containing the end-transaction control batch
     */
    public static MemoryRecords withEndTransactionMarker(long timestamp, long producerId, short producerEpoch,
                                                         EndTransactionMarker marker) {
        return withEndTransactionMarker(0L, timestamp, RecordBatch.NO_PARTITION_LEADER_EPOCH, producerId,
                producerEpoch, marker);
    }

    /**
     * Builds a {@link MemoryRecords} containing a single end-of-transaction control batch with
     * the given initial offset, timestamp, partition leader epoch, and producer identity.
     *
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param partitionLeaderEpoch the partition leader epoch
     * @param producerId           the transactional producer id
     * @param producerEpoch        the producer epoch
     * @param marker               the {@link EndTransactionMarker} describing the transaction outcome
     * @return an immutable {@link MemoryRecords} containing the end-transaction control batch
     */
    public static MemoryRecords withEndTransactionMarker(long initialOffset, long timestamp, int partitionLeaderEpoch,
                                                         long producerId, short producerEpoch,
                                                         EndTransactionMarker marker) {
        int endTxnMarkerBatchSize = DefaultRecordBatch.RECORD_BATCH_OVERHEAD + marker.endTxnMarkerValueSize();
        ByteBuffer buffer = ByteBuffer.allocate(endTxnMarkerBatchSize);
        writeEndTransactionalMarker(buffer, initialOffset, timestamp, partitionLeaderEpoch, producerId,
                producerEpoch, marker);
        buffer.flip();
        return MemoryRecords.readableRecords(buffer);
    }

    /**
     * Encodes a single end-of-transaction control batch directly into the given {@link ByteBuffer}
     * starting at its current position.
     *
     * <p>This method is a lower-level alternative to
     * {@link #withEndTransactionMarker(long, long, int, long, short, EndTransactionMarker)} for
     * callers that already manage their own buffer.
     *
     * @param buffer               the destination buffer; must have sufficient remaining capacity
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param partitionLeaderEpoch the partition leader epoch
     * @param producerId           the transactional producer id
     * @param producerEpoch        the producer epoch
     * @param marker               the {@link EndTransactionMarker} describing the transaction outcome
     */
    public static void writeEndTransactionalMarker(ByteBuffer buffer, long initialOffset, long timestamp,
                                                   int partitionLeaderEpoch, long producerId, short producerEpoch,
                                                   EndTransactionMarker marker) {
        boolean isTransactional = true;
        try (MemoryRecordsBuilder builder = new MemoryRecordsBuilder(buffer, RecordBatch.CURRENT_MAGIC_VALUE, Compression.NONE,
                TimestampType.CREATE_TIME, initialOffset, timestamp, producerId, producerEpoch,
                RecordBatch.NO_SEQUENCE, isTransactional, true, partitionLeaderEpoch,
                buffer.capacity())
        ) {
            builder.appendEndTxnMarker(timestamp, marker);
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link LeaderChangeMessage}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset       the base offset to assign to the control batch
     * @param timestamp           the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch         the partition leader epoch
     * @param buffer              the buffer to write the encoded batch into
     * @param leaderChangeMessage the {@link LeaderChangeMessage} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withLeaderChangeMessage(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        LeaderChangeMessage leaderChangeMessage
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendLeaderChangeMessage(timestamp, leaderChangeMessage);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link SnapshotHeaderRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch          the partition leader epoch
     * @param buffer               the buffer to write the encoded batch into
     * @param snapshotHeaderRecord the {@link SnapshotHeaderRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withSnapshotHeaderRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        SnapshotHeaderRecord snapshotHeaderRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendSnapshotHeaderMessage(timestamp, snapshotHeaderRecord);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link SnapshotFooterRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset        the base offset to assign to the control batch
     * @param timestamp            the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch          the partition leader epoch
     * @param buffer               the buffer to write the encoded batch into
     * @param snapshotFooterRecord the {@link SnapshotFooterRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withSnapshotFooterRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        SnapshotFooterRecord snapshotFooterRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendSnapshotFooterMessage(timestamp, snapshotFooterRecord);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link KRaftVersionRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset      the base offset to assign to the control batch
     * @param timestamp          the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch        the partition leader epoch
     * @param buffer             the buffer to write the encoded batch into
     * @param kraftVersionRecord the {@link KRaftVersionRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withKRaftVersionRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        KRaftVersionRecord kraftVersionRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendKRaftVersionMessage(timestamp, kraftVersionRecord);
            return builder.build();
        }
    }

    /**
     * Builds a {@link MemoryRecords} containing a single KRaft control batch that carries the
     * given {@link VotersRecord}. The batch is encoded using no compression and
     * {@link TimestampType#CREATE_TIME}.
     *
     * @param initialOffset the base offset to assign to the control batch
     * @param timestamp     the timestamp to embed in the batch header (milliseconds since epoch)
     * @param leaderEpoch   the partition leader epoch
     * @param buffer        the buffer to write the encoded batch into
     * @param votersRecord  the {@link VotersRecord} control record to include
     * @return an immutable {@link MemoryRecords} containing the control batch
     */
    public static MemoryRecords withVotersRecord(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer,
        VotersRecord votersRecord
    ) {
        try (MemoryRecordsBuilder builder = createKraftControlRecordBuilder(
                initialOffset,
                timestamp,
                leaderEpoch,
                buffer
            )
        ) {
            builder.appendVotersMessage(timestamp, votersRecord);
            return builder.build();
        }
    }

    private static MemoryRecordsBuilder createKraftControlRecordBuilder(
        long initialOffset,
        long timestamp,
        int leaderEpoch,
        ByteBuffer buffer
    ) {
        return new MemoryRecordsBuilder(
            buffer,
            RecordBatch.CURRENT_MAGIC_VALUE,
            Compression.NONE,
            TimestampType.CREATE_TIME,
            initialOffset,
            timestamp,
            RecordBatch.NO_PRODUCER_ID,
            RecordBatch.NO_PRODUCER_EPOCH,
            RecordBatch.NO_SEQUENCE,
            false,
            true,
            leaderEpoch,
            buffer.capacity()
        );
    }
}

