     * @param magic                the record format magic byte
     * @param initialOffset        the base offset to assign to the first record
     * @param compression          the compression codec to apply
     * @param timestampType        the timestamp type
     * @param producerId           the idempotent/transactional producer id, or
     *                             {@link RecordBatch#NO_PRODUCER_ID}
     * @param producerEpoch        the producer epoch, or {@link RecordBatch#NO_PRODUCER_EPOCH}
     * @param baseSequence         the base sequence number, or {@link RecordBatch#NO_SEQUENCE}
     * @param partitionLeaderEpoch the partition leader epoch
