import java.io.IOException;
import java.nio.ByteBuffer;
import java.nio.channels.GatheringByteChannel;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.Objects;

/**
 * A {@link Records} implementation backed by a {@link ByteBuffer}. This class is used to read or
 * modify in-place an existing, already-encoded buffer of one or more {@link RecordBatch} objects.
 *
 * <p>To <em>produce</em> new record data into a fresh buffer, use {@link MemoryRecordsBuilder} or
 * one of the static factory methods on this class (e.g.
 * {@link #builder(ByteBuffer, byte, Compression, TimestampType, long)},
 * {@link #withRecords}, {@link #withTransactionalRecords}, etc.).
 *
 * <p><b>Performance characteristics:</b>
 * <ul>
 *   <li>Batch metadata (offsets, sizes, timestamps) is read directly from the backing
 *       {@link ByteBuffer} without copying — access to header fields is O(1).</li>
 *   <li>Record-level access requires iterating and, for compressed batches, decompressing the
 *       record stream. Use {@link RecordBatch#streamingIterator(BufferSupplier)} with a buffer
 *       pool to minimise allocation pressure during decompression.</li>
 *   <li>{@link #validBytes()} is computed lazily on the first call and then cached; subsequent
 *       calls are O(1).</li>
 *   <li>{@link #buffer()} returns a {@link ByteBuffer#duplicate() duplicate} of the internal
 *       buffer — the position and limit of the returned view are independent of the internal
 *       buffer, but the underlying byte array is shared (no data copy).</li>
 *   <li>{@link #slice(int, int)} returns a zero-copy view over a sub-range of the backing
 *       buffer.</li>
 * </ul>
 *
 * <p><b>Thread-safety:</b> Instances of this class are <em>not</em> thread-safe. The backing
 * {@link ByteBuffer} is accessed without synchronisation. Additionally, in-place mutations
 * performed via {@link MutableRecordBatch} methods (e.g.
 * {@link MutableRecordBatch#setLastOffset setLastOffset},
 * {@link MutableRecordBatch#setMaxTimestamp setMaxTimestamp}) modify the shared buffer
 * in-place and must not race with concurrent readers. Callers that need to share a
 * {@code MemoryRecords} instance across threads must provide their own synchronisation.
 *
 * @see MemoryRecordsBuilder
 * @see RecordBatch
 * @see DefaultRecordBatch
 */
public class MemoryRecords extends AbstractRecords {
    public static final MemoryRecords EMPTY = MemoryRecords.readableRecords(ByteBuffer.allocate(0));

    private final ByteBuffer buffer;

    private final Iterable<MutableRecordBatch> batches = this::batchIterator;

    private int validBytes = -1;

    // Construct a writable memory records
    private MemoryRecords(ByteBuffer buffer) {
        Objects.requireNonNull(buffer, "buffer should not be null");
        this.buffer = buffer;
    }

    @Override
    public int sizeInBytes() {
        return buffer.limit();
    }

    @Override
    public int writeTo(TransferableChannel channel, int position, int length) throws IOException {
        if (((long) position) + length > buffer.limit())
            throw new IllegalArgumentException("position+length should not be greater than buffer.limit(), position: "
                    + position + ", length: " + length + ", buffer.limit(): " + buffer.limit());

        return Utils.tryWriteTo(channel, position, length, buffer);
    }

    /**
     * Write all records to the given channel (including partial records).
     *
     * <p><b>Performance note:</b> This method loops until every byte in the backing buffer has
     * been written, which may require multiple {@link GatheringByteChannel#write write} calls on
     * non-blocking channels. The internal buffer's mark/reset is used to avoid modifying the
     * visible position of the backing buffer.
     *
     * @param channel The channel to write to
     * @return The number of bytes written
     * @throws IOException For any IO errors writing to the channel
     */
    public int writeFullyTo(GatheringByteChannel channel) throws IOException {
        buffer.mark();
        int written = 0;
        while (written < sizeInBytes())
            written += channel.write(buffer);
        buffer.reset();
        return written;
    }

    /**
     * The total number of bytes in this message set not including any partial, trailing messages. This
     * may be smaller than what is returned by {@link #sizeInBytes()}.
     *
     * <p><b>Performance note:</b> The result is computed lazily on the first call by iterating
     * over all batches and summing their sizes. The computed value is cached; subsequent calls
     * return the cached result in O(1).
     *
     * @return The number of valid bytes
     */
    public int validBytes() {
        if (validBytes >= 0)
            return validBytes;

        int bytes = 0;
        for (RecordBatch batch : batches())
            bytes += batch.sizeInBytes();

        this.validBytes = bytes;
        return bytes;
    }

    @Override
    public AbstractIterator<MutableRecordBatch> batchIterator() {
        return new RecordBatchIterator<>(new ByteBufferLogInputStream(buffer.duplicate(), Integer.MAX_VALUE));
    }

    /**
     * Validates the header of the first batch and returns batch size.
     *
     * @return first batch size including LOG_OVERHEAD if buffer contains header up to
     *         magic byte, null otherwise
     * @throws CorruptRecordException if record size or magic is invalid
     */
    public Integer firstBatchSize() {
        if (buffer.remaining() < HEADER_SIZE_UP_TO_MAGIC)
            return null;
        return new ByteBufferLogInputStream(buffer, Integer.MAX_VALUE).nextBatchSize();
    }

    /**
     * Filter the records into the provided ByteBuffer.
     *
     * <p>Each batch is evaluated by the supplied {@link RecordFilter}: the filter first decides
     * at the batch level (via {@link RecordFilter#checkBatchRetention}) whether the entire batch
     * can be dropped or must be retained; for batches that pass the batch-level check, individual
     * records are evaluated via {@link RecordFilter#shouldRetainRecord}. Retained records are
     * re-serialised into {@code destinationBuffer}, potentially into a new magic v2 batch if the
     * original batch used an older format or if the delete-horizon flag needs to be set.
     *
     * <p>If the destination buffer runs out of space, a larger buffer is allocated automatically
     * and returned in {@link FilterResult#outputBuffer()}. Callers should always use the buffer
     * from {@link FilterResult#outputBuffer()} rather than the original {@code destinationBuffer}.
