     * @param producerEpoch        the producer epoch
     * @param baseSequence         the base sequence number for duplicate detection
     * @param partitionLeaderEpoch the partition leader epoch
     * @param records              the records to include; varargs
     * @return an immutable {@link MemoryRecords} containing the serialised batch
     */
    public static MemoryRecords withIdempotentRecords(long initialOffset, Compression compression, long producerId,
                                                      short producerEpoch, int baseSequence, int partitionLeaderEpoch,
                                                      SimpleRecord... records) {
        return withRecords(RecordBatch.CURRENT_MAGIC_VALUE, initialOffset, compression, TimestampType.CREATE_TIME,
                producerId, producerEpoch, baseSequence, partitionLeaderEpoch, false, records);
    }

    /**
     * Builds a {@link MemoryRecords} containing transactional records. The current magic version,
     * {@link TimestampType#CREATE_TIME}, a base offset of 0, and
     * {@link RecordBatch#NO_PARTITION_LEADER_EPOCH} are used.
     *
     * @param compression   the compression codec to apply
     * @param producerId    the transactional producer id
